// init/main.c - start_kernel() 내부 (간략화)
asmlinkage __visible void __init start_kernel(void)
{
    // 락 의존성 검증기 초기화
    lockdep_init();

    // 아키텍처별 초기화
    setup_arch(&command_line);

    // 트랩/인터럽트 벡터 초기화
    ___();

    // 메모리 관리 초기화
    mm_init();

    // 스케줄러 초기화
    ___();

    // rest_init() 호출하여 init 프로세스 생성
    rest_init();
}

// init/main.c (간략화)
static int __ref kernel_init(void *unused)
{
    // initramfs에서 init 실행 시도
    if (ramdisk_execute_command) {
        ret = run_init_process(ramdisk_execute_command);
        if (!ret)
            return 0;
    }

    // 커널 커맨드라인의 init= 파라미터 확인
    if (execute_command) {
        ret = ___(___);
        if (!ret)
            return 0;
    }

    // 기본 경로 순서대로 시도
    if (!run_init_process("/sbin/init") ||
        !run_init_process("/etc/init") ||
        !run_init_process("/bin/init") ||
        !run_init_process("/bin/sh"))
        return 0;

    ___("%s", "No working init found.");
}

